327:   static void OnExit(uv_process_t* handle,
328:                      int64_t exit_status,
329:                      int term_signal) {
330:     ProcessWrap* wrap = ContainerOf(&ProcessWrap::process_, handle);
331:     CHECK_EQ(&wrap->process_, handle);
332: 
333:     Environment* env = wrap->env();
334:     HandleScope handle_scope(env->isolate());
335:     Context::Scope context_scope(env->context());
336: 
337:     Local<Value> argv[] = {
338:       Number::New(env->isolate(), static_cast<double>(exit_status)),
339:       OneByteString(env->isolate(), signo_string(term_signal))
340:     };
341: 
342:     wrap->MakeCallback(env->onexit_string(), arraysize(argv), argv);
343:   }
